export function getBrandsForSubcategory(subcategorySlug?: string | null): { name: string; models: string[] }[] {
  if (!subcategorySlug) return [];
  const group = SUBCATEGORY_BRAND_GROUP[subcategorySlug];
  return group ? (BRAND_DATA[group] || []) : [];
}

export function getModelsForBrand(subcategorySlug: string | null | undefined, brandName: string): string[] {
  const brands = getBrandsForSubcategory(subcategorySlug);
  return brands.find((b) => b.name === brandName)?.models || [];
}
